13	# ScrollArea
14	
15	`ScrollArea` wraps a scrollable region and replaces native OS scrollbars with fully styleable custom scrollbars. The viewport still uses native scroll for accessibility and performance; the custom scrollbars are overlaid and synchronised. Supports vertical, horizontal, and both axes; four visibility modes (`Always`, `Auto`, `Hover`, `Scroll`); drag-to-scroll via thumb dragging; page-scroll via track clicks; and RTL support.
16	
17	ScrollArea MUST preserve native keyboard scrolling (arrow keys, Page Up/Down, Home/End). Custom scrollbar styling is purely visual.
18	
19	## 1. State Machine
20	
21	### 1.1 States
22	
23	```rust
24	#[derive(Clone, Debug, PartialEq, Eq, Default)]
25	pub enum State {
26	    /// No active interaction.
27	    #[default]
28	    Idle,
29	    /// User is hovering the scroll area (relevant in `Hover` mode).
30	    Hovering,
31	    /// Viewport is actively scrolling; hide timer is running.
32	    ScrollActive,
33	    /// User is dragging a scrollbar thumb.
34	    ThumbDragging,
35	}
36	```
37	
38	### 1.2 Events
39	
40	```rust
41	#[derive(Clone, Debug, PartialEq)]
42	pub enum Event {
43	    /// The viewport reported a scroll event.
44	    Scroll { x: f64, y: f64 },
45	    /// The viewport or content size changed.
46	    Resize {
47	        viewport_width: f64,
48	        viewport_height: f64,
49	        content_width: f64,
50	        content_height: f64,
51	    },
52	    /// Pointer entered the scroll area.
53	    MouseEnter,
54	    /// Pointer left the scroll area.
55	    MouseLeave,
56	    /// Pointer entered a scrollbar track.
57	    MouseEnterScrollbar,
58	    /// Pointer left a scrollbar track.
59	    MouseLeaveScrollbar,
60	    /// Thumb drag started.
61	    ThumbDragStart { pos: f64, axis: Axis },
62	    /// Thumb drag moved.
63	    ThumbDragMove { pos: f64 },
64	    /// Thumb drag ended.
65	    ThumbDragEnd,
66	    /// Click on the scrollbar track (page scroll).
67	    TrackClick { pos: f64, axis: Axis },
68	    /// Hide-delay timer fired.
69	    HideTimeout,
70	}
71	```
72	
73	### 1.3 Context
74	
75	```rust
76	/// Which scroll orientation is enabled.
77	#[derive(Clone, Debug, Copy, PartialEq, Eq, Default)]
78	pub enum ScrollOrientation {
79	    #[default]
80	    Vertical,
81	    Horizontal,
82	    Both,
83	}
84	
85	/// When scrollbars are visible.
86	#[derive(Clone, Debug, Copy, PartialEq, Eq, Default)]
87	pub enum ScrollbarVisibility {
88	    /// Always visible, whether or not content overflows.
89	    Always,
90	    /// Shown only when content overflows the viewport.
91	    #[default]
92	    Auto,
93	    /// Appear when the user hovers the scroll area.
94	    Hover,
95	    /// Appear while scrolling and fade after `hide_delay`.
96	    Scroll,
97	}
98	
99	/// Runtime context for `ScrollArea`.
100	#[derive(Clone, Debug, PartialEq)]
101	pub struct Context {
102	    pub scroll_x: f64,
103	    pub scroll_y: f64,
104	    pub viewport_width: f64,
105	    pub viewport_height: f64,
106	    pub content_width: f64,
107	    pub content_height: f64,
108	    pub scrollbar_x_visible: bool,
109	    pub scrollbar_y_visible: bool,
110	    pub hovering_scrollbar: bool,
111	    pub scrollbar_visibility: ScrollbarVisibility,
112	    pub min_thumb_size: f64,
113	    pub hide_delay_ms: u32,
114	    /// Cross-axis scrollbar thickness (px). Used to shorten track_size when
115	    /// both scrollbars are visible (the CornerSquare occupies this space).
116	    pub scrollbar_cross_size: f64,
117	    // Drag state
118	    pub drag_start_pointer_pos: f64,
119	    pub drag_start_thumb_pos: f64,
120	    pub drag_start_scroll_pos: f64,
121	    pub drag_axis: Option<Axis>,
122	    pub ids: ComponentIds,
123	    /// Resolved text direction. Drives `normalize_scroll_left` and vertical
124	    /// scrollbar placement (left side in RTL).
125	    pub dir: Direction,
126	    /// Resolved locale for message formatting.
127	    pub locale: Locale,
128	    /// Resolved translatable messages.
129	    pub messages: Messages,
130	}
131	
132	impl Context {
133	    pub fn has_overflow_x(&self) -> bool { self.content_width > self.viewport_width }
134	    pub fn has_overflow_y(&self) -> bool { self.content_height > self.viewport_height }
135	
136	    pub fn update_visibility(&mut self) {
137	        match self.scrollbar_visibility {
138	            ScrollbarVisibility::Always => {
139	                self.scrollbar_x_visible = true;
140	                self.scrollbar_y_visible = true;
141	            }
142	            ScrollbarVisibility::Auto => {
143	                self.scrollbar_x_visible = self.has_overflow_x();
144	                self.scrollbar_y_visible = self.has_overflow_y();
145	            }
146	            // Hover and Scroll are managed by state transitions.
147	            _ => {}
148	        }
149	    }
150	}
151	```
