182	    /// `scrollLeft` normalization.
183	    pub dir: Option<Direction>,
184	}
185	
186	impl Default for Props {
187	    fn default() -> Self {
188	        Self {
189	            id: String::new(),
190	            orientation: ScrollOrientation::Vertical,
191	            scrollbar_visibility: ScrollbarVisibility::Auto,
192	            min_thumb_size: None,
193	            hide_delay_ms: None,
194	            aria_label: None,
195	            dir: None,
196	        }
197	    }
198	}
199	```
200	
201	### 1.5 Thumb Metrics Computation
202	
203	```rust
204	/// Compute thumb `(size, position)` for one axis.
205	///
206	/// - `viewport_size`: visible extent of the viewport (px)
207	/// - `content_size`: total scrollable content extent (px)
208	/// - `scroll_pos`: current scroll offset (px)
209	/// - `track_size`: length of the scrollbar track (px)
210	/// - `min_thumb_size`: floor for thumb length (px)
211	///
212	/// Returns `(thumb_size, thumb_offset)`.
213	pub fn compute_thumb_metrics(
214	    viewport_size: f64,
215	    content_size: f64,
216	    scroll_pos: f64,
217	    track_size: f64,
218	    min_thumb_size: f64,
219	) -> (f64, f64) {
220	    if content_size <= viewport_size {
221	        return (track_size, 0.0);
222	    }
223	    let ratio = viewport_size / content_size;
224	    let thumb_size = (ratio * track_size).max(min_thumb_size).min(track_size);
225	    let scrollable_content = content_size - viewport_size;
226	    let scrollable_track = track_size - thumb_size;
227	    let thumb_pos = if scrollable_content > 0.0 {
228	        (scroll_pos / scrollable_content) * scrollable_track
229	    } else {
230	        0.0
231	    };
232	    (thumb_size, thumb_pos)
233	}
234	
235	/// Inverse: given a thumb position, compute the scroll position.
236	pub fn thumb_pos_to_scroll(
237	    thumb_pos: f64,
238	    track_size: f64,
239	    thumb_size: f64,
240	    content_size: f64,
241	    viewport_size: f64,
242	) -> f64 {
243	    let scrollable_track = track_size - thumb_size;
244	    let scrollable_content = content_size - viewport_size;
245	    if scrollable_track <= 0.0 { return 0.0; }
246	    (thumb_pos / scrollable_track) * scrollable_content
247	}
248	```
249	
250	### 1.6 Full Machine Implementation
251	
252	```rust
253	pub struct Machine;
254	
255	impl ars_core::Machine for Machine {
256	    type State = State;
257	    type Event = Event;
258	    type Context = Context;
259	    type Props = Props;
260	    type Messages = Messages;
261	    type Api<'a> = Api<'a>;
262	
263	    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (Self::State, Self::Context) {
264	        let locale = env.locale.clone();
265	        let messages = messages.clone();
266	        let mut ctx = Context {
267	            scroll_x: 0.0, scroll_y: 0.0,
268	            viewport_width: 0.0, viewport_height: 0.0,
269	            content_width: 0.0, content_height: 0.0,
270	            scrollbar_x_visible: false, scrollbar_y_visible: false,
271	            hovering_scrollbar: false,
272	            scrollbar_visibility: props.scrollbar_visibility,
273	            min_thumb_size: props.min_thumb_size.unwrap_or(20.0),
274	            hide_delay_ms: props.hide_delay_ms.unwrap_or(1200),
275	            scrollbar_cross_size: 0.0,
276	            drag_start_pointer_pos: 0.0,
277	            drag_start_thumb_pos: 0.0,
278	            drag_start_scroll_pos: 0.0,
279	            drag_axis: None,
280	            ids: ComponentIds::from_id(&props.id),
281	            dir: props.dir.unwrap_or(Direction::Ltr),
282	            locale,
283	            messages,
284	        };
285	        ctx.update_visibility();
286	        (State::Idle, ctx)
287	    }
288	
289	    fn transition(
290	        state: &Self::State,
291	        event: &Self::Event,
292	        ctx: &Self::Context,
293	        props: &Self::Props,
294	    ) -> Option<TransitionPlan<Self>> {
295	        match event {
296	            Event::Resize { viewport_width, viewport_height, content_width, content_height } => {
297	                let (vw, vh, cw, ch) = (*viewport_width, *viewport_height, *content_width, *content_height);
298	                Some(TransitionPlan::context_only(move |ctx| {
299	                    ctx.viewport_width = vw; ctx.viewport_height = vh;
300	                    ctx.content_width = cw; ctx.content_height = ch;
301	                    ctx.update_visibility();
302	                }))
303	            }
304	
305	            Event::Scroll { x, y } => {
306	                let (sx, sy) = (*x, *y);
307	                if ctx.scrollbar_visibility == ScrollbarVisibility::Scroll {
308	                    let delay = ctx.hide_delay_ms;
309	                    Some(TransitionPlan::to(State::ScrollActive).apply(move |ctx| {
310	                        ctx.scroll_x = sx; ctx.scroll_y = sy;
311	                        ctx.scrollbar_x_visible = ctx.has_overflow_x();
312	                        ctx.scrollbar_y_visible = ctx.has_overflow_y();
313	                    }).with_named_effect("auto-hide-scrollbar", move |_ctx, _props, send| {
314	                        let platform = use_platform_effects();
315	                        let handle = platform.set_timeout(delay, Box::new(move || send(Event::HideTimeout)));
316	                        let pc = platform.clone();
317	                        Box::new(move || pc.clear_timeout(handle))
318	                    }))
319	                } else {
320	                    Some(TransitionPlan::context_only(move |ctx| {
321	                        ctx.scroll_x = sx; ctx.scroll_y = sy;
322	                    }))
323	                }
324	            }
325	
326	            Event::MouseEnter => {
327	                if ctx.scrollbar_visibility == ScrollbarVisibility::Hover {
328	                    Some(TransitionPlan::to(State::Hovering).apply(|ctx| {
329	                        ctx.scrollbar_x_visible = ctx.has_overflow_x();
330	                        ctx.scrollbar_y_visible = ctx.has_overflow_y();
331	                    }))
332	                } else { None }
333	            }
334	
335	            Event::MouseLeave => {
336	                if ctx.scrollbar_visibility == ScrollbarVisibility::Hover && !ctx.hovering_scrollbar {
337	                    Some(TransitionPlan::to(State::Idle).apply(|ctx| {
338	                        ctx.scrollbar_x_visible = false; ctx.scrollbar_y_visible = false;
339	                    }))
340	                } else { None }
341	            }
342	
343	            Event::MouseEnterScrollbar => Some(TransitionPlan::context_only(|ctx| { ctx.hovering_scrollbar = true; })),
344	            Event::MouseLeaveScrollbar => Some(TransitionPlan::context_only(|ctx| { ctx.hovering_scrollbar = false; })),
345	
346	            Event::HideTimeout => {
347	                if *state != State::ThumbDragging {
348	                    Some(TransitionPlan::to(State::Idle).apply(|ctx| {
349	                        ctx.scrollbar_x_visible = false; ctx.scrollbar_y_visible = false;
350	                    }))
351	                } else { None }
352	            }
353	
354	            Event::ThumbDragStart { pos, axis } => {
355	                let (p, a) = (*pos, *axis);
356	                let scroll_pos = match a { Axis::X => ctx.scroll_x, Axis::Y => ctx.scroll_y };
357	                let (viewport_size, content_size, track_size) = axis_metrics(ctx, a);
358	                let min_thumb = ctx.min_thumb_size;
359	                Some(TransitionPlan::to(State::ThumbDragging).apply(move |ctx| {
360	                    ctx.drag_start_pointer_pos = p;
361	                    let (_, current_thumb_pos) = compute_thumb_metrics(
362	                        viewport_size, content_size, scroll_pos, track_size, min_thumb,
363	                    );
364	                    ctx.drag_start_thumb_pos = current_thumb_pos;
365	                    ctx.drag_start_scroll_pos = scroll_pos;
366	                    ctx.drag_axis = Some(a);
367	                }))
368	            }
369	
370	            Event::ThumbDragMove { pos } => {
371	                if *state != State::ThumbDragging { return None; }
372	                let axis = ctx.drag_axis?;
373	                let p = *pos;
374	                let (drag_start_pointer, drag_start_thumb, drag_scroll, min_thumb) =
375	                    (ctx.drag_start_pointer_pos, ctx.drag_start_thumb_pos, ctx.drag_start_scroll_pos, ctx.min_thumb_size);
376	                let (viewport_size, content_size, track_size) = axis_metrics(ctx, axis);
377	                let delta = p - drag_start_pointer;
378	                let (thumb_size, _) = compute_thumb_metrics(viewport_size, content_size, drag_scroll, track_size, min_thumb);
379	                let new_thumb_pos = (drag_start_thumb + delta).max(0.0);
380	                let new_scroll = thumb_pos_to_scroll(new_thumb_pos, track_size, thumb_size, content_size, viewport_size);
381	                Some(TransitionPlan::context_only(move |ctx| {
382	                    match axis { Axis::X => ctx.scroll_x = new_scroll, Axis::Y => ctx.scroll_y = new_scroll }
383	                }))
384	            }
385	
386	            Event::ThumbDragEnd => {
387	                Some(TransitionPlan::to(State::Idle).apply(|ctx| { ctx.drag_axis = None; }))
388	            }
389	
390	            Event::TrackClick { pos, axis } => {
391	                let (a, p) = (*axis, *pos);
392	                let scroll_pos = match a { Axis::X => ctx.scroll_x, Axis::Y => ctx.scroll_y };
393	                let (viewport_size, content_size, track_size) = axis_metrics(ctx, a);
394	                let (thumb_size, thumb_pos) = compute_thumb_metrics(viewport_size, content_size, scroll_pos, track_size, ctx.min_thumb_size);
395	                let new_scroll = if p < thumb_pos {
396	                    (scroll_pos - viewport_size).max(0.0)
397	                } else if p > thumb_pos + thumb_size {
398	                    (scroll_pos + viewport_size).min(content_size - viewport_size)
399	                } else { scroll_pos };
400	                Some(TransitionPlan::context_only(move |ctx| {
401	                    match a { Axis::X => ctx.scroll_x = new_scroll, Axis::Y => ctx.scroll_y = new_scroll }
402	                }))
403	            }
404	        }
405	    }
406	
407	    fn connect<'a>(
408	        state: &'a State, ctx: &'a Context, props: &'a Props, send: &'a dyn Fn(Event),
409	    ) -> Api<'a> {
410	        Api { state, ctx, props, send }
411	    }
412	}
413	
414	/// Helper: get (viewport_size, content_size, track_size) for an axis,
415	/// accounting for the cross-axis scrollbar's CornerSquare gap.
416	fn axis_metrics(ctx: &Context, axis: Axis) -> (f64, f64, f64) {
417	    match axis {
418	        Axis::X => {
419	            let cross = if ctx.scrollbar_y_visible { ctx.scrollbar_cross_size } else { 0.0 };
420	            (ctx.viewport_width, ctx.content_width, ctx.viewport_width - cross)
421	        }
422	        Axis::Y => {
423	            let cross = if ctx.scrollbar_x_visible { ctx.scrollbar_cross_size } else { 0.0 };
424	            (ctx.viewport_height, ctx.content_height, ctx.viewport_height - cross)
425	        }
426	    }
427	}
428	```
429	
430	### 1.7 Connect / API
431	
432	```rust
433	#[derive(ComponentPart)]
434	#[scope = "scroll-area"]
435	pub enum Part {
436	    Root,
437	    Viewport,
438	    Content,
439	    ScrollbarY,
440	    ThumbY,
441	    ScrollbarX,
442	    ThumbX,
443	    CornerSquare,
444	}
445	
446	pub struct Api<'a> {
447	    state: &'a State,
448	    ctx: &'a Context,
449	    props: &'a Props,
450	    send: &'a dyn Fn(Event),
451	}
452	
453	impl<'a> Api<'a> {
454	    /// Whether the viewport is scrolled to the top edge.
455	    pub fn is_at_top(&self) -> bool { self.ctx.scroll_y <= 0.0 }
456	
457	    /// Whether the viewport is scrolled to the bottom edge.
458	    pub fn is_at_bottom(&self) -> bool {
459	        self.ctx.scroll_y >= (self.ctx.content_height - self.ctx.viewport_height).max(0.0)
460	    }
461	
462	    /// Whether the viewport is scrolled to the left edge.
463	    pub fn is_at_left(&self) -> bool { self.ctx.scroll_x <= 0.0 }
464	
465	    /// Whether the viewport is scrolled to the right edge.
466	    pub fn is_at_right(&self) -> bool {
467	        self.ctx.scroll_x >= (self.ctx.content_width - self.ctx.viewport_width).max(0.0)
468	    }
469	
470	    /// Current scroll progress as `(x, y)` in the range `0.0..=1.0`.
471	    pub fn scroll_progress(&self) -> (f64, f64) {
472	        let px = if self.ctx.content_width > self.ctx.viewport_width {
