    pub fn on_root_mouseenter(&self) { (self.send)(Event::MouseEnter); }
    pub fn on_root_mouseleave(&self) { (self.send)(Event::MouseLeave); }
    pub fn on_scrollbar_mouseenter(&self) { (self.send)(Event::MouseEnterScrollbar); }
