1	//! Collapsible layout component.
2	//!
3	//! `Collapsible` owns DOM-free disclosure state, semantic relationships, and
4	//! adapter-consumable animation intent. Framework adapters keep live element
5	//! handles for measurement and transition listeners.
6	
7	use alloc::{string::String, vec::Vec};
8	use core::fmt::{self, Debug};
9	
10	use ars_core::{
11	    AriaAttr, AttrMap, Bindable, ComponentIds, ComponentMessages, ComponentPart, ConnectApi,
12	    CssProperty, Env, HtmlAttr, KeyboardKey, Locale, MessageFn, NoEffect, TransitionPlan,
13	};
14	use ars_interactions::KeyboardEventData;
15	
16	/// States of the `Collapsible`.
17	#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, Hash)]
18	pub enum State {
19	    /// The content region is visible.
20	    Open,
21	
22	    /// The content region is hidden.
23	    #[default]
24	    Closed,
25	}
26	
27	/// Events sent to the `Collapsible`.
28	#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
29	pub enum Event {
30	    /// Toggle between open and closed states.
31	    Toggle,
32	
33	    /// Programmatically set the open state.
34	    SetOpen(bool),
35	
36	    /// The trigger or content received focus.
37	    Focus {
38	        /// Whether the focus is received via keyboard.
39	        is_keyboard: bool,
40	    },
41	
42	    /// The trigger or content lost focus.
43	    Blur,
44	
45	    /// Synchronize prop-backed context fields.
46	    SyncProps,
47	
48	    /// Synchronize the controlled open value.
49	    SyncControlledOpen(bool),
50	}
51	
52	/// Runtime context for the `Collapsible` state machine.
53	#[derive(Clone, Debug, PartialEq)]
54	pub struct Context {
55	    /// Whether the collapsible is open.
56	    pub open: Bindable<bool>,
57	
58	    /// Whether the trigger is non-interactive and toggle is suppressed.
59	    pub disabled: bool,
60	
61	    /// Whether the trigger currently has focus.
62	    pub focused: bool,
63	
64	    /// Whether focus was received via keyboard.
65	    pub focus_visible: bool,
66	
67	    /// Component identifiers for ARIA attribute generation.
68	    pub ids: ComponentIds,
69	
70	    /// CSS height to expose while closed for partial-content layouts.
71	    pub collapsed_height: Option<String>,
72	
73	    /// CSS width to expose while closed for horizontal partial-content layouts.
74	    pub collapsed_width: Option<String>,
75	
76	    /// Resolved locale for message formatting.
77	    pub locale: Locale,
78	
79	    /// Resolved translatable messages.
80	    pub messages: Messages,
81	}
82	
83	/// Configuration props for the `Collapsible` component.
84	#[derive(Clone, Debug, Default, PartialEq, ars_core::HasId)]
85	pub struct Props {
86	    /// The id of the component.
87	    pub id: String,
88	
89	    /// Controlled open state.
90	    pub open: Option<bool>,
91	
92	    /// Initial open state for uncontrolled usage.
93	    pub default_open: bool,
94	
95	    /// Disables interaction when `true`.
96	    pub disabled: bool,
97	
98	    /// Adapter hint: content is not mounted until first opened.
99	    pub lazy_mount: bool,
100	
101	    /// Adapter hint: content is removed from the DOM after collapsing.
102	    pub unmount_on_exit: bool,
103	
104	    /// CSS height to expose when collapsed instead of fully hiding content.
105	    pub collapsed_height: Option<String>,
106	
107	    /// CSS width to expose when collapsed instead of fully hiding content.
108	    pub collapsed_width: Option<String>,
109	}
110	
111	impl Props {
112	    /// Returns fresh collapsible props with documented defaults.
113	    ///
114	    /// # Examples
115	    ///
116	    /// ```
117	    /// use ars_components::layout::collapsible::{Machine, Messages, Props};
118	    /// use ars_core::{Env, HtmlAttr, Service};
119	    ///
120	    /// let service = Service::<Machine>::new(
121	    ///     Props::new().id("details").default_open(true),
122	    ///     &Env::default(),
123	    ///     &Messages::default(),
124	    /// );
125	    /// let attrs = service.connect(&|_| {}).root_attrs();
126	    ///
127	    /// assert_eq!(attrs.get(&HtmlAttr::Data("ars-state")), Some("open"));
128	    /// ```
129	    #[must_use]
130	    pub fn new() -> Self {
131	        Self::default()
132	    }
133	
134	    /// Sets the component instance ID.
135	    #[must_use]
136	    pub fn id(mut self, id: impl Into<String>) -> Self {
137	        self.id = id.into();
138	        self
139	    }
140	
141	    /// Sets [`open`](Self::open), making the collapsible controlled at mount.
142	    #[must_use]
143	    pub const fn open(mut self, open: bool) -> Self {
144	        self.open = Some(open);
145	        self
146	    }
147	
148	    /// Clears [`open`](Self::open), making the collapsible uncontrolled.
149	    #[must_use]
150	    pub const fn uncontrolled(mut self) -> Self {
151	        self.open = None;
152	        self
153	    }
154	
155	    /// Sets [`default_open`](Self::default_open).
156	    #[must_use]
157	    pub const fn default_open(mut self, default_open: bool) -> Self {
158	        self.default_open = default_open;
159	        self
160	    }
161	
162	    /// Sets [`disabled`](Self::disabled).
163	    #[must_use]
164	    pub const fn disabled(mut self, disabled: bool) -> Self {
165	        self.disabled = disabled;
166	        self
167	    }
168	
169	    /// Sets [`lazy_mount`](Self::lazy_mount).
170	    #[must_use]
171	    pub const fn lazy_mount(mut self, lazy_mount: bool) -> Self {
172	        self.lazy_mount = lazy_mount;
173	        self
174	    }
175	
176	    /// Sets [`unmount_on_exit`](Self::unmount_on_exit).
177	    #[must_use]
178	    pub const fn unmount_on_exit(mut self, unmount_on_exit: bool) -> Self {
179	        self.unmount_on_exit = unmount_on_exit;
180	        self
181	    }
182	
183	    /// Sets [`collapsed_height`](Self::collapsed_height).
184	    #[must_use]
185	    pub fn collapsed_height(mut self, collapsed_height: impl Into<String>) -> Self {
186	        self.collapsed_height = Some(collapsed_height.into());
187	        self
188	    }
189	
190	    /// Sets [`collapsed_width`](Self::collapsed_width).
191	    #[must_use]
192	    pub fn collapsed_width(mut self, collapsed_width: impl Into<String>) -> Self {
193	        self.collapsed_width = Some(collapsed_width.into());
194	        self
195	    }
196	}
197	
198	/// Localized messages for [`Collapsible`](self).
199	#[derive(Clone, Debug, PartialEq)]
200	pub struct Messages {
201	    /// Accessible label for the trigger when collapsed.
202	    pub expand_label: MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
203	
204	    /// Accessible label for the trigger when expanded.
205	    pub collapse_label: MessageFn<dyn Fn(&Locale) -> String + Send + Sync>,
206	}
207	
208	impl Default for Messages {
209	    fn default() -> Self {
210	        Self {
211	            expand_label: MessageFn::static_str("Show content"),
212	            collapse_label: MessageFn::static_str("Hide content"),
213	        }
214	    }
215	}
216	
217	impl ComponentMessages for Messages {}
218	
219	/// The machine for the `Collapsible` component.
220	#[derive(Debug)]
221	pub struct Machine;
222	
223	impl ars_core::Machine for Machine {
224	    type State = State;
225	    type Event = Event;
226	    type Context = Context;
227	    type Props = Props;
228	    type Messages = Messages;
229	    type Effect = NoEffect;
230	    type Api<'a> = Api<'a>;
231	
232	    fn init(
233	        props: &Self::Props,
234	        env: &Env,
235	        messages: &Self::Messages,
236	    ) -> (Self::State, Self::Context) {
237	        let initial_open = props.open.unwrap_or(props.default_open);
238	        let state = state_from_bool(initial_open);
239	
240	        let open = if let Some(value) = props.open {
241	            Bindable::controlled(value)
242	        } else {
243	            Bindable::uncontrolled(initial_open)
244	        };
245	
246	        (
247	            state,
248	            Context {
249	                open,
250	                disabled: props.disabled,
251	                focused: false,
252	                focus_visible: false,
253	                ids: ComponentIds::from_id(&props.id),
254	                collapsed_height: props.collapsed_height.clone(),
255	                collapsed_width: props.collapsed_width.clone(),
256	                locale: env.locale.clone(),
257	                messages: messages.clone(),
258	            },
259	        )
260	    }
261	
262	    fn transition(
263	        state: &Self::State,
264	        event: &Self::Event,
265	        ctx: &Self::Context,
266	        props: &Self::Props,
267	    ) -> Option<TransitionPlan<Self>> {
268	        match event {
269	            Event::Toggle if !ctx.disabled => open_transition(ctx, !ctx.open.get()),
270	
271	            Event::SetOpen(value) if !ctx.disabled => open_transition(ctx, *value),
272	
273	            Event::Focus { is_keyboard } => {
274	                let is_keyboard = *is_keyboard;
275	                if ctx.focused && ctx.focus_visible == is_keyboard {
276	                    return None;
277	                }
278	
279	                Some(TransitionPlan::context_only(move |ctx: &mut Context| {
280	                    ctx.focused = true;
281	                    ctx.focus_visible = is_keyboard;
282	                }))
283	            }
284	
285	            Event::Blur => {
286	                if !ctx.focused && !ctx.focus_visible {
287	                    return None;
288	                }
289	
290	                Some(TransitionPlan::context_only(|ctx: &mut Context| {
291	                    ctx.focused = false;
292	                    ctx.focus_visible = false;
293	                }))
294	            }
295	
296	            Event::SyncProps => Some(sync_props_plan(ctx, props)),
297	
298	            Event::SyncControlledOpen(value) => {
299	                let value = *value;
300	                let next = state_from_bool(value);
301	
302	                let mut next_open = ctx.open.clone();
303	                next_open.set(value);
304	                next_open.sync_controlled(Some(value));
305	
306	                if ctx.open == next_open && state == &next {
307	                    return None;
308	                }
309	
310	                Some(TransitionPlan::to(next).apply(move |ctx: &mut Context| {
311	                    ctx.open.set(value);
312	                    ctx.open.sync_controlled(Some(value));
313	                }))
314	            }
315	
316	            _ => None,
317	        }
318	    }
319	
320	    fn connect<'a>(
321	        state: &'a Self::State,
322	        ctx: &'a Self::Context,
323	        props: &'a Self::Props,
324	        send: &'a dyn Fn(Self::Event),
325	    ) -> Self::Api<'a> {
326	        Api {
327	            state,
328	            ctx,
329	            props,
330	            send,
331	        }
332	    }
333	
334	    fn on_props_changed(old: &Self::Props, new: &Self::Props) -> Vec<Self::Event> {
335	        assert_eq!(
336	            old.id, new.id,
337	            "collapsible::Props.id must remain stable after init"
338	        );
339	
340	        let mut events = Vec::new();
341	
342	        let prop_backed_context_changed = old.disabled != new.disabled
343	            || old.collapsed_height != new.collapsed_height
344	            || old.collapsed_width != new.collapsed_width
345	            || (old.open.is_some() && new.open.is_none());
346	
347	        if prop_backed_context_changed {
348	            events.push(Event::SyncProps);
349	        }
350	
351	        if old.open != new.open
352	            && let Some(open) = new.open
353	        {
354	            events.push(Event::SyncControlledOpen(open));
355	        }
356	
357	        events
358	    }
359	}
360	
361	/// Structural parts exposed by the `Collapsible` connect API.
362	#[derive(ComponentPart)]
363	#[scope = "collapsible"]
364	pub enum Part {
365	    /// The root collapsible container.
366	    Root,
367	
368	    /// The button that toggles the content region.
369	    Trigger,
370	
371	    /// Optional visual indicator for the current open state.
372	    Indicator,
373	
374	    /// The expandable content region.
375	    Content,
376	}
377	
378	/// Connected Collapsible API.
379	pub struct Api<'a> {
380	    state: &'a State,
381	    ctx: &'a Context,
382	    props: &'a Props,
383	    send: &'a dyn Fn(Event),
384	}
385	
386	impl Debug for Api<'_> {
387	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
388	        f.debug_struct("Api")
389	            .field("state", self.state)
390	            .field("ctx", self.ctx)
391	            .field("props", self.props)
392	            .finish()
393	    }
394	}
395	
396	impl Api<'_> {
397	    /// Whether the collapsible is currently open.
398	    #[must_use]
399	    pub fn is_open(&self) -> bool {
400	        self.state == &State::Open
401	    }
402	
403	    /// Attributes for the root container element.
404	    #[must_use]
405	    pub fn root_attrs(&self) -> AttrMap {
406	        let mut attrs = AttrMap::new();
407	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
408	
409	        attrs
410	            .set(scope_attr, scope_val)
411	            .set(part_attr, part_val)
412	            .set(HtmlAttr::Id, self.ctx.ids.id())
413	            .set(HtmlAttr::Data("ars-state"), state_token(self.is_open()));
414	
415	        if self.ctx.disabled {
416	            attrs.set_bool(HtmlAttr::Data("ars-disabled"), true);
417	        }
418	
419	        attrs
420	    }
421	
422	    /// Attributes for the trigger button.
423	    #[must_use]
424	    pub fn trigger_attrs(&self) -> AttrMap {
425	        let mut attrs = AttrMap::new();
426	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Trigger.data_attrs();
427	
428	        let label = if self.is_open() {
429	            (self.ctx.messages.collapse_label)(&self.ctx.locale)
430	        } else {
431	            (self.ctx.messages.expand_label)(&self.ctx.locale)
432	        };
433	
434	        attrs
435	            .set(HtmlAttr::Id, self.trigger_id())
436	            .set(scope_attr, scope_val)
437	            .set(part_attr, part_val)
438	            .set(HtmlAttr::Type, "button")
439	            .set(HtmlAttr::Data("ars-state"), state_token(self.is_open()))
440	            .set(
441	                HtmlAttr::Aria(AriaAttr::Expanded),
442	                bool_token(self.is_open()),
443	            )
444	            .set(HtmlAttr::Aria(AriaAttr::Controls), self.content_id())
445	            .set(HtmlAttr::Aria(AriaAttr::Label), label);
446	
447	        if self.ctx.disabled {
448	            attrs
449	                .set_bool(HtmlAttr::Disabled, true)
450	                .set_bool(HtmlAttr::Data("ars-disabled"), true);
451	        }
452	
453	        if self.ctx.focused {
454	            attrs.set_bool(HtmlAttr::Data("ars-focus"), true);
455	        }
456	
457	        if self.ctx.focus_visible {
458	            attrs.set_bool(HtmlAttr::Data("ars-focus-visible"), true);
459	        }
460	
461	        attrs
462	    }
463	
464	    /// Attributes for an optional visual indicator.
465	    #[must_use]
466	    pub fn indicator_attrs(&self) -> AttrMap {
467	        let mut attrs = AttrMap::new();
468	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Indicator.data_attrs();
469	
470	        attrs
471	            .set(scope_attr, scope_val)
472	            .set(part_attr, part_val)
473	            .set(HtmlAttr::Data("ars-state"), state_token(self.is_open()))
474	            .set(HtmlAttr::Aria(AriaAttr::Hidden), "true");
475	
476	        attrs
477	    }
478	
479	    /// Attributes for the content region.
480	    #[must_use]
481	    pub fn content_attrs(&self) -> AttrMap {
482	        let mut attrs = AttrMap::new();
483	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Content.data_attrs();
484	
485	        let has_collapsed_size =
486	            self.ctx.collapsed_height.is_some() || self.ctx.collapsed_width.is_some();
487	
488	        attrs
489	            .set(HtmlAttr::Id, self.content_id())
490	            .set(scope_attr, scope_val)
491	            .set(part_attr, part_val)
492	            .set(HtmlAttr::Role, "region")
493	            .set(HtmlAttr::Aria(AriaAttr::LabelledBy), self.trigger_id())
494	            .set(HtmlAttr::Data("ars-state"), state_token(self.is_open()));
495	
496	        if !self.is_open() && !has_collapsed_size {
497	            attrs.set_bool(HtmlAttr::Hidden, true);
498	        }
499	
500	        if let Some(height) = &self.ctx.collapsed_height {
501	            attrs.set_style(
502	                CssProperty::Custom("ars-collapsible-collapsed-height"),
503	                height,
504	            );
505	        }
506	
507	        if let Some(width) = &self.ctx.collapsed_width {
508	            attrs.set_style(
509	                CssProperty::Custom("ars-collapsible-collapsed-width"),
510	                width,
511	            );
512	        }
513	
514	        if has_collapsed_size {
515	            attrs.set_bool(HtmlAttr::Data("ars-collapsed-size"), true);
516	        }
517	
518	        attrs
519	    }
520	
521	    /// Adapter handler: the trigger was clicked.
522	    pub fn on_trigger_click(&self) {
523	        if !self.ctx.disabled {
524	            (self.send)(Event::Toggle);
525	        }
526	    }
527	
528	    /// Adapter handler: a key was pressed on the trigger.
529	    ///
530	    /// Returns `true` when the key was handled so adapters can prevent the
531	    /// native button activation click and avoid dispatching a duplicate toggle.
532	    pub fn on_trigger_keydown(&self, data: &KeyboardEventData) -> bool {
533	        if !self.ctx.disabled
534	            && !data.repeat
535	            && (data.key == KeyboardKey::Enter || data.key == KeyboardKey::Space)
536	        {
537	            (self.send)(Event::Toggle);
538	            return true;
539	        }
540	
541	        false
542	    }
543	
544	    /// Adapter handler: the trigger received focus.
545	    pub fn on_trigger_focus(&self, is_keyboard: bool) {
546	        if !self.ctx.disabled {
547	            (self.send)(Event::Focus { is_keyboard });
548	        }
549	    }
550	
551	    /// Adapter handler: the trigger lost focus.
552	    pub fn on_trigger_blur(&self) {
553	        (self.send)(Event::Blur);
554	    }
555	
556	    fn trigger_id(&self) -> String {
557	        self.ctx.ids.part("trigger")
558	    }
559	
560	    fn content_id(&self) -> String {
561	        self.ctx.ids.part("content")
562	    }
563	}
564	
565	impl ConnectApi for Api<'_> {
566	    type Part = Part;
567	
568	    fn part_attrs(&self, part: Self::Part) -> AttrMap {
569	        match part {
570	            Part::Root => self.root_attrs(),
571	            Part::Trigger => self.trigger_attrs(),
572	            Part::Indicator => self.indicator_attrs(),
573	            Part::Content => self.content_attrs(),
574	        }
575	    }
576	}
577	
578	fn open_transition(ctx: &Context, value: bool) -> Option<TransitionPlan<Machine>> {
579	    if ctx.open.is_controlled() {
580	        return Some(TransitionPlan::context_only(move |ctx: &mut Context| {
581	            ctx.open.set(value);
582	        }));
583	    }
584	
585	    if ctx.open.get() == &value {
586	        return None;
587	    }
588	
589	    Some(
590	        TransitionPlan::to(state_from_bool(value)).apply(move |ctx: &mut Context| {
591	            ctx.open.set(value);
592	        }),
593	    )
594	}
595	
596	fn sync_props_plan(ctx: &Context, props: &Props) -> TransitionPlan<Machine> {
597	    let disabled = props.disabled;
598	    let collapsed_height = props.collapsed_height.clone();
599	    let collapsed_width = props.collapsed_width.clone();
600	    let was_controlled = ctx.open.is_controlled();
601	    let leaving_controlled = was_controlled && props.open.is_none();
602	    let visible_open = *ctx.open.get();
603	
604	    let target_state = if leaving_controlled {
605	        Some(state_from_bool(visible_open))
606	    } else {
607	        None
608	    };
609	
610	    let mut plan = if let Some(state) = target_state {
611	        TransitionPlan::to(state)
612	    } else {
613	        TransitionPlan::new()
614	    };
615	
616	    plan = plan.apply(move |ctx: &mut Context| {
617	        ctx.disabled = disabled;
618	        ctx.collapsed_height = collapsed_height;
619	        ctx.collapsed_width = collapsed_width;
620	
621	        if leaving_controlled {
622	            ctx.open.set(visible_open);
623	            ctx.open.sync_controlled(None);
624	        }
625	
626	        if ctx.disabled {
627	            ctx.focused = false;
628	            ctx.focus_visible = false;
629	        }
630	    });
631	
632	    plan
633	}
