fn thumb_drag_clamps_scroll_to_content_bounds() {
    let mut service = service(props());
    resize(&mut service, 100.0, 100.0, 100.0, 400.0);

    drop(service.send(Event::ThumbDragStart {
        pos: 0.0,
        axis: Axis::Y,
